{{PLUGIN_METHODS}}.example:
async getCurrentWeather(data) {
  this.validateParams(data, {
    location: { required: true, type: 'string' }
  });

  const response = await fetch(`${this.config.baseUrl}/current?q=${data.location}&key=${this.config.apiKey}`);
  return await response.json();
}

